                if (tog) { tog.textContent = gearEnabled ? '已開啟' : '已關閉'; tog.className = 'as-bt afk-ui-toggle' + (gearEnabled ? ' active' : ''); tog.setAttribute('aria-pressed', gearEnabled ? 'true' : 'false'); }
