                if (reserveBody) reserveBody.hidden = !reserveOpen;
                var reserveCount = reserveToggle.querySelector('em');
                if (reserveCount) reserveCount.textContent = reserveCount.textContent.replace(/[▾▸]\s*$/, reserveOpen ? '▾' : '▸');
